cards.solution_code:
def parse_age(s):
    try:
        n = int(s)
    except ValueError:
        raise ValueError('age must be a non-negative integer') from None
    if n < 0:
        raise ValueError('age must be a non-negative integer')
    if n > 150:
        raise ValueError('age out of range')
    return n

